sql:
SELECT operator, taxi_model, COUNT(*) AS taxi_count
FROM taxis
GROUP BY operator, taxi_model;

external_knowledge:
- "captains the ship" refers to the taxi operator;
- "farthest journey" corresponds to the longest duration of a trip;
- "stormy seas of traffic" metaphorically describes the trips taken on roads with varying traffic conditions.

sql:
SELECT * 
FROM call_types 
WHERE call_type_description = 'Booked';

SELECT COUNT(*) 
FROM taxis 
WHERE status = 'active';

SELECT AVG(average_speed)
FROM trip_statistics
WHERE fare > 20 AND duration < 15;

SELECT DISTINCT taxi_id
FROM trips
WHERE actual_arrival_time < estimated_arrival_time AND duration > (SELECT AVG(duration) FROM trips);

SELECT trip_id, call_type
FROM trips
ORDER BY trip_id;

SELECT AVG(distance) AS average_distance
FROM trips
WHERE call_type = 'B' AND rating > 8;

SELECT AVG(fare) AS Average_Fare
FROM trip_statistics
WHERE driver_id < 500;
